// // This module implements a 4-bit binary counter with asynchronous reset and disable that decrements its value by 2 on every negative clock edge when disable is low.
module counter_by_2(CLK, RST, EN, COUNT);
input CLK, RST, EN;
output reg [3:0] COUNT;

always @(posedge CLK or posedge RST) begin
    if (RST)
        COUNT <= 4'b0000;
    else if (EN)
        COUNT <= COUNT + 2;
end

endmodule
